import React, { useRef, useState } from 'react'

function useTicTacToe() {
    const initialBoard = Array(9).fill(null)
    const [board, setBoard] = useState([...initialBoard])
    const [isNextX, setIsNextX] = useState(true)
    const [statusText, setStatusText] = useState('')
    const winningRef = useRef([])
    const winnerRef = useRef(null)
    const WINNING_PATTERN = [
        [0, 1, 2],
        [3, 4, 5],
        [6, 7, 8],
        [0, 3, 6],
        [1, 4, 7],
        [2, 5, 8],
        [0, 4, 8],
        [2, 4, 6]
    ]

    function calculateWinner() {
        for (let i = 0; i < WINNING_PATTERN.length; i++) {
            const [a, b, c] = WINNING_PATTERN[i]
            if (board[a] && board[a] === board[b] && board[b] === board[c]) {
                winningRef.current = WINNING_PATTERN[i]
                winnerRef.current = board[a]
                getStatus()
            }
        }
    }
    function reset() {
        winningRef.current = []
        setBoard([...initialBoard])
    }

    function handleClick(index) {
        if (winnerRef.current || board[index]) return
        calculateWinner()
        setBoard((prevBoard) => {
            prevBoard[index] = isNextX ? 'X' : 'O'
            return prevBoard
        })
        setIsNextX((prev) => !prev)
        getStatus()
    }

    function getStatus() {
        if (winnerRef.current) setStatusText(`Winner is: ${winnerRef.current}`)
        if (!board.includes(null)) setStatusText('Its a draw')
        calculateWinner()
        setStatusText(`Next turn: ${isNextX ? 'X' : 'O'}`)
    }

    return [board, getStatus, statusText, handleClick, reset, winningRef]

}

function Board() {
    const [board, statusText, handleClick, reset, winningRef] = useTicTacToe()
    const boxesStyle = {
        padding: '50px',
        display: 'grid',
        gridTemplateColumns: '1fr 1fr 1fr',
        width: 'fit-content'
    }

    const boxStyle = {
        width: '50px',
        height: '50px',
        border: '1px solid grey'
    }
    return (
        <>
            <button onClick={reset}>Start</button>
            <p>{statusText}</p>
            <div style={{ ...boxesStyle }}>
                {board.map((box, idx) => {
                    return <div
                        onClick={() => handleClick(idx)}
                        key={`Box_${idx}`}
                        style={{ backgroundColor: winningRef.current.includes(idx) ? 'green' : 'white', ...boxStyle }}
                        className='box'>{box}</div>
                })}
            </div >
        </>
    )
}

export default Board
